def histogram(test):
    """Given a string representing space-separated uppercase letters, return a set
    of the letter(s) with the least repetitions and their corresponding counts.
    If several letters have the same occurrence, return only one of them.

    Example:
    histogram('A B C') == {'A': 1}
    histogram('A B B A') == {'B': 2}
    histogram('A B C A B') == {'C': 1}
    histogram('B B B B A') == {'A': 1}
    histogram('') == {'': 0}
    """
    from collections import Counter

    # Handle empty input
    if not test:
        return {'': 0}

    # Split the input by spaces and count occurrences
    letters = test.split()
    count = Counter(letters)

    # Determine the minimum occurrence
    min_count = min(count.values())

    # Create a set of all letters that have the minimum count
    result = {letter: cnt for letter, cnt in count.items() if cnt == min_count}

    return result

# Explanation:
# 1. The function uses the Counter class from the collections module to count occurrences of each letter in the input string.
# 2. It splits the input string into individual letters using the split() method.
# 3. The minimum occurrence is determined using the min() function on the values from the Counter.
# 4. A result dictionary is created to include all letters that have this minimum occurrence, ensuring that only one letter with the least count is returned.
